const input = $input.first().json;

// تحديد نوع التحديث: رسالة عادية أم ضغطة زر
const isCallback = !!input.callback_query;
const isMessage = !!input.message;

let result = {
  updateType: 'unknown',
  messageType: 'unknown',
  text: '',
  chatId: null,
  username: '',
  firstName: '',
  callbackData: '',
  callbackQueryId: '',
  messageId: null
};

if (isCallback) {
  // الطالب ضغط زر
  const cb = input.callback_query;
  result.updateType = 'callback_query';
  result.chatId = cb.from.id;
  result.username = cb.from.username || '';
  result.firstName = cb.from.first_name || '';
  result.callbackData = cb.data || '';
  result.callbackQueryId = cb.id;
  result.messageId = cb.message?.message_id || null;

  // تحديد نوع الـ callback
  if (cb.data === 'attendance_present') {
    result.messageType = 'attendance_present';
  } else if (cb.data === 'attendance_absent') {
    result.messageType = 'attendance_absent';
  } else {
    result.messageType = 'callback_unknown';
  }

} else if (isMessage) {
  // رسالة عادية
  const message = input.message;
  const text = (message.text || '').trim();
  result.updateType = 'message';
  result.chatId = message.chat.id;
  result.username = message.chat.username || '';
  result.firstName = message.chat.first_name || '';
  result.text = text;
  result.messageId = message.message_id;

  if (text === '/start') {
    result.messageType = 'start_command';
  } else if (/^05\d{8}$/.test(text)) {
    result.messageType = 'phone_number';
  } else {
    result.messageType = 'regular_message';
  }
}

return result;

const now = new Date();
const dayOfWeek = now.getDay();
// 0=الأحد، 1=الإثنين، 2=الثلاثاء، 3=الأربعاء، 4=الخميس، 5=الجمعة، 6=السبت

let targetGroup = '';
const targetPeriod = 'فترة أولى';

if ([6, 1, 3].includes(dayOfWeek)) {
  // أيام المجموعة A
  targetGroup = 'A';
} else if ([0, 2, 4].includes(dayOfWeek)) {
  // أيام المجموعة B
  targetGroup = 'B';
}

return {
  targetGroup: targetGroup,
  targetPeriod: targetPeriod,
  currentTime: now.toISOString(),
  dayOfWeek: dayOfWeek
};

// الفترة الثانية تكون فقط في أيام المجموعة A (السبت، الإثنين، الأربعاء)
// وللشباب فقط
return {
  targetGroup: 'C',
  targetPeriod: 'فترة ثانية',
  currentTime: new Date().toISOString()
};

const now = new Date();
// تحويل لتوقيت غزة (UTC+2 أو UTC+3 حسب الصيف)
// نستخدم Asia/Gaza
const gazaTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Gaza' }));

const dayOfWeek = gazaTime.getDay();
const hours = gazaTime.getHours();
const minutes = gazaTime.getMinutes();
const totalMinutes = hours * 60 + minutes;

// نوافذ الحضور:
// الفترة الأولى: 9:00 - 9:15 = On Time | 9:15 - 12:00 = Late | بعد ذلك = Out of Window
// الفترة الثانية: 12:00 - 12:15 = On Time | 12:15 - 3:00 = Late | بعد ذلك = Out of Window

// تحديد أي فترة الطالب فيها بناءً على الوقت الحالي
let period = '';
let status = ''; // On Time / Late / Out of Window
let isValidDay = false;

// الجمعة (5) عطلة
if (dayOfWeek === 5) {
  status = 'Out of Window';
  period = 'Holiday';
}
// الفترة الأولى (9:00 - 12:00) — كل الأيام عدا الجمعة
else if (totalMinutes >= 9 * 60 && totalMinutes < 12 * 60) {
  period = 'فترة أولى';
  isValidDay = true;

  if (totalMinutes < 9 * 60 + 15) {
    status = 'On Time';
  } else {
    status = 'Late';
  }
}
// الفترة الثانية (12:00 - 15:00) — فقط السبت/الإثنين/الأربعاء
else if (totalMinutes >= 12 * 60 && totalMinutes < 15 * 60) {
  if ([6, 1, 3].includes(dayOfWeek)) {
    period = 'فترة ثانية';
    isValidDay = true;

    if (totalMinutes < 12 * 60 + 15) {
      status = 'On Time';
    } else {
      status = 'Late';
    }
  } else {
    status = 'Out of Window';
    period = 'No Afternoon Today';
  }
}
// خارج كل النوافذ
else {
  status = 'Out of Window';
  period = 'Outside Hours';
}

return {
  chatId: $input.first().json.chatId,
  callbackQueryId: $input.first().json.callbackQueryId,
  messageId: $input.first().json.messageId,
  attendanceStatus: status, // On Time / Late / Out of Window
  detectedPeriod: period,
  currentTime: gazaTime.toISOString(),
  dayOfWeek: dayOfWeek,
  totalMinutes: totalMinutes
};

