const now = new Date();
const gazaTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Gaza' }));

const dayOfWeek = gazaTime.getDay();
const hours = gazaTime.getHours();
const minutes = gazaTime.getMinutes();
const totalMinutes = hours * 60 + minutes;

// نوافذ الإنجاز:
// الفترة الأولى: 11:45 - 12:00 (15 دقيقة)
// الفترة الثانية: 14:45 - 15:00 (15 دقيقة)

let achievementWindow = false;
let detectedPeriod = '';

// الجمعة عطلة
if (dayOfWeek === 5) {
  achievementWindow = false;
}
// نافذة الفترة الأولى (11:45 - 12:00) — كل الأيام عدا الجمعة
else if (totalMinutes >= 11 * 60 + 45 && totalMinutes < 12 * 60) {
  achievementWindow = true;
  detectedPeriod = 'فترة أولى';
}
// نافذة الفترة الثانية (14:45 - 15:00) — السبت/الإثنين/الأربعاء
else if (totalMinutes >= 14 * 60 + 45 && totalMinutes < 15 * 60) {
  if ([6, 1, 3].includes(dayOfWeek)) {
    achievementWindow = true;
    detectedPeriod = 'فترة ثانية';
  }
}

// التحقق من جودة النص
const text = $input.first().json.text || '';
const textLength = text.trim().length;
const needsReview = textLength < 20; // نص قصير جداً = يحتاج مراجعة

return {
  chatId: $input.first().json.chatId,
  messageId: $input.first().json.messageId,
  text: text,
  textLength: textLength,
  needsReview: needsReview,
  isInAchievementWindow: achievementWindow,
  detectedPeriod: detectedPeriod,
  currentTime: gazaTime.toISOString(),
  todayDate: gazaTime.toISOString().split('T')[0] // YYYY-MM-DD
};

